    raw_output: interpretacao
  }
};

const historyText = clean(historico.history_text, true);
const historyForBruna = clean(historico.history_for_agent, true);
const knowledge = readKnowledgeContext();
const businessNeed = classifyBusinessKnowledgeNeed(finalContent);

const knowledgeQuery = [
  finalContent,
  businessNeed.intents.length ? `Intenções: ${businessNeed.intents.join(", ")}` : "",
  historyForBruna ? `Contexto recente: ${historyForBruna.split("\n").slice(-6).join(" | ")}` : ""
].filter(Boolean).join("\n");

const agent = {
  ...asObject(entrada.agent),
  ...asObject($json.agent),
  history_text: historyText,
  history_for_agent: historyForBruna,
  history_source: "chatwoot_subworkflow",
  current_message_after_interpretation: finalContent,
  needs_business_knowledge: businessNeed.needs_business_knowledge,
  business_knowledge_intents: businessNeed.intents,
  knowledge_query: knowledgeQuery,
  knowledge_context: knowledge.context,
